<?php
namespace App\Http\Controllers\AdminDinas;
use App\Http\Controllers\Controller;use App\Models\{RegionReference,Umkm,UmkmUpdateSubmission};use App\Services\Audit\AuditLogger;use App\Services\Location\MapProviderService;use Illuminate\Http\Request;
class LocationController extends Controller { public function edit(Umkm $umkm, MapProviderService $map){ $provinces=RegionReference::query()->where('region_level','province')->where('is_active',true)->orderBy('region_name')->get(['id','region_name']); return view('pages.admin-dinas.location.edit',compact('umkm','provinces'))->with('mapConfig',$map->config()); } public function submitProposal(Request $r, Umkm $umkm, AuditLogger $audit){ abort_unless($umkm->status_data==='resmi',422,'Usulan lokasi hanya untuk data resmi.'); $v=$r->validate(['province_region_id'=>'required|integer|exists:region_references,id','city_region_id'=>'required|integer|exists:region_references,id','district_region_id'=>'required|integer|exists:region_references,id','village_region_id'=>'required|integer|exists:region_references,id','address_detail'=>'required|string|max:500','latitude'=>'required|numeric|between:-90,90','longitude'=>'required|numeric|between:-180,180']); $proposal=UmkmUpdateSubmission::query()->create(['umkm_id'=>$umkm->id,'submitted_by'=>$r->user()->id,'old_data'=>['location'=>'existing'],'new_data'=>['location'=>$v],'submission_payload'=>['type'=>'location_update']+$v,'status_data'=>'diajukan','submitted_at'=>now()]); $audit->log('umkm.location.proposal.create',$r,'umkm_update_submissions',$proposal->id,[],$proposal->toArray()); return back()->with('status','Usulan lokasi diajukan.'); } public function adminValidate(Request $r, UmkmUpdateSubmission $proposal, AuditLogger $audit){ abort_unless($proposal->status_data==='diajukan',422,'Proposal hanya bisa divalidasi dari status diajukan.'); $v=$r->validate(['decision'=>'required|in:disetujui,perlu_perbaikan,ditolak','review_note'=>'nullable|string|max:1000']); $before=$proposal->toArray(); $proposal->update(['status_data'=>$v['decision'],'review_notes'=>$v['review_note'] ?? null,'reviewed_by'=>$r->user()->id,'reviewed_at'=>now()]); $audit->log('umkm.location.proposal.review',$r,'umkm_update_submissions',$proposal->id,$before,$proposal->fresh()->toArray()); return back()->with('status','Validasi lokasi tersimpan.'); }}
